+    private CancellationTokenSource? _cts;
+    private string _lastLoadedTrackingNumber = string.Empty;
+
+    protected override async Task OnParametersSetAsync()
+    {
+        if (string.Equals(TrackingNumber, _lastLoadedTrackingNumber, StringComparison.OrdinalIgnoreCase))
+        {
+            return;
+        }
+
+        await LoadShipmentAsync();
+    }
+
+    private async Task LoadShipmentAsync()
+    {
+        // Cancel any in-flight request
+        CancelPendingRequest();
+
+        _cts = new CancellationTokenSource();
+        _lastLoadedTrackingNumber = TrackingNumber;
+        _shipment = null;
+        _errorMessage = null;
+        _loading = true;
+
+        try
+        {
+            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, _cts.Token);
+        }
+        catch (OperationCanceledException)
+        {
+            // Request was cancelled (navigation or dispose) — do nothing
+            return;
